using ChurnPredictor;
using Microsoft.Extensions.ML;
using Microsoft.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train and save the model at startup ---
var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
IDataView allData = mlContext.Data.LoadFromTextFile<ChurnInput>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnInput.Age),
        nameof(ChurnInput.Income),
        "RegionEncoded",
        nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers
        .SdcaLogisticRegression(labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on the held-out test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                  $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");
mlContext.Model.Save(model, allData.Schema, modelPath);

// Register the pooled prediction engine (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnPrediction> pool, ChurnInput input) =>
{
    var result = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = result.Churned,
        result.Probability,
        result.Score
    });
});

app.Run();

